     8→export async function findCommitForCheckpoint(
     9→  repoPath: string,
    10→  branch: string,
    11→  checkpointId: string,
    12→): Promise<{ hash: string; subject: string; branch: string; authorName: string; authorEmail: string } | null> {
    13→  const branches = [branch, "main", "master"].filter(
    14→    (b, i, arr) => arr.indexOf(b) === i,
    15→  );
    16→
    17→  for (const b of branches) {
    18→    let commits: Awaited<ReturnType<typeof gitlog>>;
    19→    try {
    20→      commits = await gitlog({
    21→        repo: repoPath,
    22→        branch: b,
    23→        fields: ["hash", "subject", "body", "authorName", "authorEmail"] as const,
    24→        number: 10_000,
    25→      });
    26→    } catch {
    27→      continue;
    28→    }
    29→
    30→    for (const commit of commits) {
    31→      const id = getCheckpointIdFromCommitMessage(commit.body ?? "");
    32→      if (id === checkpointId) {
    33→        return {
    34→          hash: commit.hash,
    35→          subject: commit.subject,
    36→          branch: b,
    37→          authorName: commit.authorName,
    38→          authorEmail: commit.authorEmail,
    39→        };
    40→      }
    41→    }
    42→  }
    43→
    44→  return null;
    45→}
