     6→// ─── Singleton DB cache ───────────────────────────────────────────────────────
     7→
     8→const dbCache = new Map<string, PrismaClient>();
     9→
    10→/**
    11→ * Open (or return cached) a PrismaClient backed by a better-sqlite3 file at `dbPath`.
    12→ * Runs PRAGMA journal_mode=WAL for safe concurrent writes.
    13→ */
    14→export async function getDb(dbPath: string): Promise<PrismaClient> {
    15→  const abs = resolve(dbPath);
    16→  const cached = dbCache.get(abs);
    17→  if (cached) return cached;
    18→
    19→  mkdirSync(dirname(abs), { recursive: true });
    20→
    21→  const adapter = new PrismaBetterSqlite3({ url: `file:${abs}` });
    22→  const db = new PrismaClient({ adapter } as ConstructorParameters<typeof PrismaClient>[0]);
    23→
    24→  try {
    25→    await db.$queryRawUnsafe("PRAGMA journal_mode=WAL");
    26→  } catch {
    27→    // Non-fatal — WAL mode is a performance hint
    28→  }
    29→
    30→  dbCache.set(abs, db);
    31→  return db;
    32→}
