   167→async function createTokenUsage(db: PrismaClient, tu: Record<string, unknown>): Promise<number> {
   168→  const row = await db.tokenUsage.create({
   169→    data: {
   170→      inputTokens:         Number(tu.input_tokens          ?? 0),
   171→      cacheCreationTokens: Number(tu.cache_creation_tokens ?? 0),
   172→      cacheReadTokens:     Number(tu.cache_read_tokens     ?? 0),
   173→      outputTokens:        Number(tu.output_tokens         ?? 0),
   174→      apiCallCount:        Number(tu.api_call_count        ?? 0),
   175→    },
   176→  });
   177→  return row.id;
   178→}
   179→
   180→// ─── V2 single-checkpoint indexer ────────────────────────────────────────────
   181→
   182→/**
   183→ * Index one checkpoint directory using the new normalized schema.
   184→ *
   185→ * Reads:
   186→ *   <checkpointDir>/metadata.json             → CheckpointMetadata
   187→ *   <checkpointDir>/<n>/metadata.json         → CheckpointSessionMetadata
   188→ *   <checkpointDir>/<n>/content_hash.txt      → SessionLink.contentHash (actual hash)
   189→ *   <checkpointDir>/<n>/{full.jsonl,context.md,prompt.txt} → SessionLink paths
   190→ */
   191→export async function indexCheckpointV2(
   192→  db: PrismaClient,
   193→  checkpointDir: string,
   194→  checkpointId: string,
   195→  repoPath?: string,
   196→  mappedCheckpointIds?: Set<string>,
   197→): Promise<void> {
   198→  const metaPath = join(checkpointDir, "metadata.json");
   199→  if (!existsSync(metaPath)) throw new Error(`No metadata.json at ${checkpointDir}`);
   200→
   201→  const meta = JSON.parse(readFileSync(metaPath, "utf8")) as RootMeta;
   202→
   203→  // Upsert CheckpointMetadata — create TokenUsage only on first insert
   204→  let checkpointMeta = await db.checkpointMetadata.findUnique({
   205→    where: { checkpointId },
   206→    select: { id: true },
   207→  });
   208→
   209→  if (!checkpointMeta) {
   210→    let tokenUsageId: number | null = null;
   211→    if (meta.token_usage) tokenUsageId = await createTokenUsage(db, meta.token_usage);
   212→    checkpointMeta = await db.checkpointMetadata.create({
   213→      data: {
   214→        checkpointId,
   215→        cliVersion:       meta.cli_version       ?? null,
   216→        branch:           meta.branch            ?? null,
   217→        strategy:         meta.strategy          ?? null,
   218→        checkpointsCount: meta.checkpoints_count ?? 0,
   219→        tokenUsageId,
   220→      },
   221→      select: { id: true },
   222→    });
   223→  } else {
   224→    await db.checkpointMetadata.update({
   225→      where: { checkpointId },
   226→      data: {
   227→        cliVersion:       meta.cli_version       ?? null,
   228→        branch:           meta.branch            ?? null,
   229→        strategy:         meta.strategy          ?? null,
   230→        checkpointsCount: meta.checkpoints_count ?? 0,
   231→      },
   232→    });
   233→  }
   234→
   235→  // files_touched → FilePath + join table
   236→  for (const filePath of meta.files_touched ?? []) {
   237→    const filePathId = await upsertFilePath(db, filePath);
   238→    await db.checkpointMetadataFilePath.upsert({
   239→      where: { checkpointMetadataId_filePathId: { checkpointMetadataId: checkpointMeta.id, filePathId } },
   240→      create: { checkpointMetadataId: checkpointMeta.id, filePathId },
   241→      update: {},
   242→    });
   243→  }
   244→
   245→  // Session sub-directories: 0/, 1/, …
   246→  const sessionDirs = readdirSync(checkpointDir)
   247→    .filter((e) => /^\d+$/.test(e) && statSync(join(checkpointDir, e)).isDirectory())
   248→    .sort((a, b) => parseInt(a) - parseInt(b));
