    43→function getGitUser(cwd?: string): { name: string | null; email: string | null } {
    44→  // Try local config first (cwd), then fall back to global
    45→  const name  = (cwd ? gitConfigGet("user.name", cwd)  : null) ?? gitConfigGet("--global user.name");
    46→  const email = (cwd ? gitConfigGet("user.email", cwd) : null) ?? gitConfigGet("--global user.email");
