    82→// SQLite has a limit of 999 bind variables per statement. When doing IN queries
    83→// over large sets, chunk and union the results.
    84→const SQLITE_IN_CHUNK = 500;
    85→
    86→async function findManyInChunks<T>(
    87→  ids: string[],
    88→  fetch: (chunk: string[]) => Promise<T[]>,
    89→): Promise<T[]> {
    90→  if (ids.length === 0) return [];
    91→  const results: T[] = [];
    92→  for (let i = 0; i < ids.length; i += SQLITE_IN_CHUNK) {
    93→    const chunk = ids.slice(i, i + SQLITE_IN_CHUNK);
    94→    results.push(...await fetch(chunk));
    95→  }
    96→  return results;
    97→}
