     5→export interface RepoConfig {
     6→  name: string;
     7→  remote: string;
     8→  localPath: string;
     9→  dbPath: string;
    10→}
    11→
    12→export interface GossamerConfig {
    13→  repos: RepoConfig[];
    14→}
    15→
    16→const CONFIG_DIR  = join(homedir(), ".gossamer");
    17→const CONFIG_PATH = join(CONFIG_DIR, "config.json");
    18→
    19→export function getConfigPath(): string {
    20→  return CONFIG_PATH;
    21→}
    22→
    23→export function readConfig(): GossamerConfig {
    24→  if (!existsSync(CONFIG_PATH)) {
    25→    return { repos: [] };
    26→  }
    27→  const raw = readFileSync(CONFIG_PATH, "utf-8");
    28→  return JSON.parse(raw) as GossamerConfig;
    29→}
    30→
    31→export function writeConfig(config: GossamerConfig): void {
    32→  mkdirSync(CONFIG_DIR, { recursive: true });
    33→  writeFileSync(CONFIG_PATH, JSON.stringify(config, null, 2), "utf-8");
    34→}
    35→
    36→export function addRepo(repo: RepoConfig): void {
    37→  const config = readConfig();
    38→  const existing = config.repos.findIndex((r) => r.localPath === repo.localPath);
    39→  if (existing >= 0) {
    40→    config.repos[existing] = repo;
    41→  } else {
    42→    config.repos.push(repo);
    43→  }
    44→  writeConfig(config);
    45→}
    46→
    47→export function removeRepo(localPath: string): void {
    48→  const config = readConfig();
    49→  config.repos = config.repos.filter((r) => r.localPath !== localPath);
    50→  writeConfig(config);
    51→}
    52→
    53→export function findRepo(localPath: string): RepoConfig | undefined {
    54→  return readConfig().repos.find((r) => r.localPath === localPath);
    55→}
    56→
    57→/** Derive a default DB path for a new repo: ~/.gossamer/repos/<name>.db */
    58→export function defaultDbPath(name: string): string {
    59→  const safe = name.replace(/[^a-zA-Z0-9_-]/g, "_");
    60→  return join(CONFIG_DIR, "repos", `${safe}.db`);
    61→}
