   121→  // Resolve git user and repo name from repo config once at startup
   122→  const gitUser  = getGitUser(repoDir);
   123→  const repoName = repoDir ? basename(repoDir) : null;
   124→
   125→  // GET /api/sessions — reconstructed from CheckpointSessionMetadata + ShadowSession
   126→  app.get("/api/sessions", async (_req, res) => {
   127→    try {
   128→      // Latest checkpoint meta per sessionId (asc order so map always ends on latest)
   129→      const allMetas = await db.checkpointSessionMetadata.findMany({
   130→        select: {
   131→          sessionId: true,
   132→          checkpointId: true,
   133→          branch: true,
   134→          summary: { select: { intent: true } },
   135→        },
   136→        orderBy: { createdAt: "asc" },
   137→      });
   138→      const cpMap = new Map<string, { branch: string | null; intent: string | null; checkpointId: string }>();
   139→      for (const m of allMetas) {
   140→        cpMap.set(m.sessionId, { branch: m.branch, intent: m.summary?.intent ?? null, checkpointId: m.checkpointId });
   141→      }
   142→
   143→      // Git user per checkpoint (from commit author stored at index time)
   144→      const allCheckpointIds = [...new Set(allMetas.map((m) => m.checkpointId))];
   145→      const cpUserRows = allCheckpointIds.length > 0
   146→        ? await db.checkpointMetadata.findMany({
   147→            where: { checkpointId: { in: allCheckpointIds } },
   148→            select: { checkpointId: true, gitUserName: true, gitUserEmail: true },
   149→          })
   150→        : [];
   151→      const cpUserMap = new Map(cpUserRows.map((r) => [r.checkpointId, r]));
   152→
   153→      const shadows = await db.shadowSession.findMany();
   154→      const shadowMap = new Map(shadows.map((s) => [s.sessionId, s]));
   155→
   156→      const showArchived = _req.query.archived === "1";
   157→      const archivedRows = await db.archivedSession.findMany({ select: { sessionId: true } });
   158→      const archivedSet = new Set(archivedRows.map((r) => r.sessionId));
   159→
   160→      // Also include sessions visible only from LogEvent (hook-written, not yet indexed)
   161→      const knownIds = new Set([...cpMap.keys(), ...shadows.map((s) => s.sessionId)]);
   162→      const logEventSessionRows = await db.logEvent.findMany({
   163→        distinct: ["sessionId"],
   164→        where: { sessionId: { not: null } },
   165→        select: { sessionId: true },
   166→      });
   167→      for (const r of logEventSessionRows) {
   168→        if (r.sessionId && !knownIds.has(r.sessionId)) knownIds.add(r.sessionId);
   169→      }
   170→
   171→      const allIds = [...knownIds]
   172→        .filter((id) => showArchived ? archivedSet.has(id) : !archivedSet.has(id));
   173→      if (allIds.length === 0) {
   174→        res.json([]);
   175→        return;
   176→      }
   177→
   178→      // Min/max LogEvent timestamps per session
   179→      const times = await db.logEvent.groupBy({
   180→        by: ["sessionId"],
   181→        where: { sessionId: { in: allIds }, timestamp: { not: null } },
   182→        _min: { timestamp: true },
   183→        _max: { timestamp: true },
   184→      });
   185→      const timeMap = new Map(
   186→        times.map((r) => [r.sessionId!, { startedAt: r._min.timestamp, updatedAt: r._max.timestamp }])
   187→      );
   188→
   189→      // First cwd per session
   190→      const cwdRows = await db.logEvent.findMany({
   191→        where: { sessionId: { in: allIds }, cwd: { not: null } },
   192→        distinct: ["sessionId"],
   193→        orderBy: { id: "asc" },
   194→        select: { sessionId: true, cwd: true },
   195→      });
   196→      const cwdMap = new Map(cwdRows.map((e) => [e.sessionId!, e.cwd]));
   197→
   198→      // Parent-child relationships from task checkpoints
   199→      const allParentRows = await db.sessionParent.findMany({
   200→        select: { childSessionId: true, parentSessionId: true },
   201→      });
   202→      const parentMap = new Map(allParentRows.map((r) => [r.childSessionId, r.parentSessionId]));
   203→      const childMap = new Map<string, string[]>();
   204→      for (const r of allParentRows) {
   205→        if (!childMap.has(r.parentSessionId)) childMap.set(r.parentSessionId, []);
   206→        childMap.get(r.parentSessionId)!.push(r.childSessionId);
   207→      }
   208→
   209→      const result: SessionResponse[] = allIds.map((sessionId) => {
   210→        const cp     = cpMap.get(sessionId) ?? null;
   211→        const shadow = shadowMap.get(sessionId) ?? null;
   212→        const t      = timeMap.get(sessionId);
   213→        const startedAt = t?.startedAt ?? shadow?.createdAt ?? null;
   214→        const updatedAt = t?.updatedAt ?? shadow?.createdAt ?? null;
   215→        const cpUser = cp ? cpUserMap.get(cp.checkpointId) ?? null : null;
   216→        return {
   217→          sessionId,
   218→          startedAt: startedAt?.toISOString() ?? new Date(0).toISOString(),
   219→          updatedAt: updatedAt?.toISOString() ?? new Date(0).toISOString(),
   220→          cwd:             cwdMap.get(sessionId) ?? shadow?.cwd ?? "",
   221→          repoRoot:        repoDir ?? null,
   222→          repoName:        repoName,
   223→          parentSessionId: parentMap.get(sessionId) ?? null,
   224→          childSessionIds: childMap.get(sessionId) ?? [],
   225→          gitUserName:     cpUser?.gitUserName ?? gitUser.name,
   226→          gitUserEmail:    cpUser?.gitUserEmail ?? gitUser.email,
   227→          prompt:          shadow?.prompt ?? null,
   228→          summary:         null,
   229→          keywords:        [],
   230→          branch:          cp?.branch ?? shadow?.gitBranch ?? null,
   231→          intent:          cp?.intent ?? null,
   232→          isLive:          shadow !== null,
   233→        };
   234→      });
   235→
   236→      result.sort((a, b) => b.updatedAt.localeCompare(a.updatedAt));
   237→      res.json(result);
   238→    } catch (err) {
   239→      res.status(500).json({ error: String(err) });
   240→    }
   241→  });
   242→
   243→  // GET /api/sessions/:id
   244→  app.get("/api/sessions/:id", async (req, res) => {
   245→    try {
   246→      const id = req.params.id;
   247→      const [latestMeta, shadow, firstEvent, lastEvent] = await Promise.all([
   248→        db.checkpointSessionMetadata.findFirst({
   249→          where: { sessionId: id },
   250→          select: { branch: true, checkpointId: true, summary: { select: { intent: true } } },
   251→          orderBy: { createdAt: "desc" },
   252→        }),
   253→        db.shadowSession.findUnique({ where: { sessionId: id } }),
   254→        db.logEvent.findFirst({
   255→          where: { sessionId: id },
   256→          orderBy: { id: "asc" },
   257→          select: { cwd: true, timestamp: true },
   258→        }),
   259→        db.logEvent.findFirst({
   260→          where: { sessionId: id, timestamp: { not: null } },
   261→          orderBy: { id: "desc" },
   262→          select: { timestamp: true },
   263→        }),
   264→      ]);
   265→      if (!latestMeta && !shadow) {
   266→        res.status(404).json({ error: "Session not found" });
   267→        return;
   268→      }
   269→      const cpMeta = latestMeta
   270→        ? await db.checkpointMetadata.findUnique({
   271→            where: { checkpointId: latestMeta.checkpointId },
   272→            select: { gitUserName: true, gitUserEmail: true },
   273→          })
   274→        : null;
   275→      const startedAt = firstEvent?.timestamp ?? shadow?.createdAt ?? null;
   276→      const updatedAt = lastEvent?.timestamp  ?? shadow?.createdAt ?? null;
   277→      res.json({
   278→        sessionId:       id,
   279→        startedAt:       startedAt?.toISOString() ?? new Date(0).toISOString(),
   280→        updatedAt:       updatedAt?.toISOString() ?? new Date(0).toISOString(),
   281→        cwd:             firstEvent?.cwd ?? shadow?.cwd ?? "",
   282→        repoRoot:        repoDir ?? null,
   283→        repoName:        repoName,
   284→        parentSessionId: null,
   285→        childSessionIds: [],
   286→        gitUserName:     cpMeta?.gitUserName ?? gitUser.name,
   287→        gitUserEmail:    cpMeta?.gitUserEmail ?? gitUser.email,
   288→        prompt:          shadow?.prompt ?? null,
   289→        summary:         null,
   290→        keywords:        [],
   291→        branch:          latestMeta?.branch ?? shadow?.gitBranch ?? null,
   292→        intent:          latestMeta?.summary?.intent ?? null,
   293→        isLive:          shadow !== null,
   294→      } satisfies SessionResponse);
   295→    } catch (err) {
   296→      res.status(500).json({ error: String(err) });
   297→    }
   298→  });
