     1→import { app, BrowserWindow, ipcMain } from "electron";
     2→import { join } from "path";
     3→import { spawn } from "child_process";
     4→import type { ChildProcess } from "child_process";
     5→
     6→let serverProc: ChildProcess | null = null;
     7→
     8→function startServer(): void {
     9→  const launcherPath = join(process.resourcesPath, "server", "server-launcher.cjs");
    10→
    11→  // Run the Electron binary as a plain Node.js process (ELECTRON_RUN_AS_NODE=1).
    12→  // This gives the server full Node.js access with the same ABI as the main
    13→  // process, so native modules rebuilt for Electron work without a separate node binary.
    14→  serverProc = spawn(process.execPath, [launcherPath], {
    15→    env: { ...process.env, ELECTRON_RUN_AS_NODE: "1" },
    16→    stdio: ["ignore", "pipe", "pipe"],
    17→  });
    18→
    19→  serverProc.stdout?.on("data", (d: Buffer) => process.stdout.write(`[server] ${d}`));
    20→  serverProc.stderr?.on("data", (d: Buffer) => process.stderr.write(`[server] ${d}`));
    21→  serverProc.on("exit", (code, signal) =>
    22→    console.error(`[server] exited code=${code} signal=${signal}`)
    23→  );
    24→}
    25→
    26→function createWindow(tabParam?: string): void {
    27→  const win = new BrowserWindow({
    28→    width: 1400,
    29→    height: 900,
    30→    webPreferences: {
    31→      preload: join(__dirname, "../preload/index.js"),
    32→      contextIsolation: true,
    33→      nodeIntegration: false,
    34→    },
    35→  });
    36→
    37→  const tabQuery = tabParam ? `?tab=${encodeURIComponent(tabParam)}` : "";
    38→
    39→  if (process.env.ELECTRON_RENDERER_URL) {
    40→    win.loadURL(`${process.env.ELECTRON_RENDERER_URL}${tabQuery}`);
    41→    win.webContents.openDevTools();
    42→  } else {
    43→    win.loadFile(join(__dirname, "../renderer/index.html"), {
    44→      query: tabParam ? { tab: tabParam } : undefined,
    45→    });
    46→  }
    47→}
    48→
    49→app.whenReady().then(() => {
    50→  // In dev mode the server is started separately via `npm run serve`.
    51→  if (!process.env.ELECTRON_RENDERER_URL) {
    52→    startServer();
    53→  }
    54→
    55→  ipcMain.handle("open-window", (_event, tabParam: string) => {
    56→    createWindow(tabParam);
    57→  });
    58→
    59→  createWindow();
    60→});
    61→
    62→app.on("window-all-closed", () => {
    63→  serverProc?.kill("SIGTERM");
    64→  if (process.platform !== "darwin") app.quit();
    65→});
    66→
    67→app.on("will-quit", () => {
    68→  serverProc?.kill("SIGTERM");
    69→});
    70→
    71→app.on("activate", () => {
    72→  if (BrowserWindow.getAllWindows().length === 0) createWindow();
    73→});
