    40→export function groupClaudeTurns(items: DisplayItem[]): RenderItem[] {
    41→  const result: RenderItem[] = [];
    42→  let i = 0;
    43→  while (i < items.length) {
    44→    const item = items[i];
    45→    if (item.kind === "toolGroup") {
    46→      const toolGroups: ToolUseData[][] = [];
    47→      while (i < items.length && items[i].kind === "toolGroup") {
    48→        toolGroups.push((items[i] as { kind: "toolGroup"; tools: ToolUseData[] }).tools);
    49→        i++;
    50→      }
    51→      let stop: Event | null = null;
    52→      if (i < items.length && items[i].kind === "event" && (items[i] as { kind: "event"; event: Event }).event.event === "Stop") {
    53→        stop = (items[i] as { kind: "event"; event: Event }).event;
    54→        i++;
    55→      }
    56→      result.push({ kind: "claudeTurn", toolGroups, stop });
    57→    } else if (item.kind === "event" && item.event.event === "Stop") {
    58→      result.push({ kind: "claudeTurn", toolGroups: [], stop: item.event });
    59→      i++;
    60→    } else if (item.kind === "checkpoint") {
    61→      result.push({ kind: "checkpoint", checkpoint: item.checkpoint });
    62→      i++;
    63→    } else {
    64→      result.push({ kind: "event", event: (item as { kind: "event"; event: Event }).event });
    65→      i++;
    66→    }
    67→  }
    68→  return result;
    69→}
