   750→function gitExec(args: string, cwd: string): string {
   751→  return execSync(`git ${args}`, {
   752→    cwd,
   753→    encoding: "utf8",
   754→    stdio: ["ignore", "pipe", "ignore"],
   755→    maxBuffer: 64 * 1024 * 1024,
   756→  });
