import React, { useEffect, useState } from "react";
import { Text, Center, Loader } from "@mantine/core";

// TODO: import and wire up the existing Electron app screens
// (ActiveSessions, SessionDetail, etc.) — they communicate via
// vscode.postMessage / window.addEventListener("message") instead of
// the HTTP/WebSocket API used by the Electron app.

type AppState = "loading" | "ready";

export function App() {
  const [state, setState] = useState<AppState>("loading");

  useEffect(() => {
    const handler = (event: MessageEvent) => {
      const msg = event.data as { type: string };
      if (msg.type === "indexed") {
        setState("ready");
      }
    };
    window.addEventListener("message", handler);
    return () => window.removeEventListener("message", handler);
  }, []);

  if (state === "loading") {
    return (
      <Center h="100vh">
        <Loader />
      </Center>
    );
  }

  return (
    <Center h="100vh">
      <Text>Gossamer is ready. Screens go here.</Text>
    </Center>
  );
}

