    67→          <ActionIcon
    68→            size="xs"
    69→            variant="subtle"
    70→            color={copied ? "green" : "gray"}
    71→            onClick={copy}
    72→            style={{ position: "absolute", right: 4, top: "50%", transform: "translateY(-50%)" }}
    73→          >
    74→            {copied ? "✓" : "⧉"}
    75→          </ActionIcon>
    76→        </Tooltip>
    77→      )}
