    87→  const [archiving, setArchiving] = useState(false);
    88→
    89→  return (
    90→    <Table.Tr onClick={onPress} style={{ cursor: "pointer" }}>
    91→        <CopyCell copyValue={intent} width={COL_WIDTHS.intent}>
    92→          <div style={{ display: "flex", alignItems: "center", gap: 6, overflow: "hidden" }}>
    93→            <Tooltip label={dot.label} withArrow position="left" openDelay={300}>
    94→              <div style={{ width: 8, height: 8, borderRadius: "50%", backgroundColor: dot.color, flexShrink: 0 }} />
    95→            </Tooltip>
    96→            <Text size="sm" style={{ overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{intent}</Text>
    97→            {session.isLive && (
    98→              <Badge size="xs" color="orange" variant="light" style={{ flexShrink: 0 }}>
    99→                live
   100→              </Badge>
   101→            )}
   102→          </div>
   103→        </CopyCell>
   104→
   105→        <CopyCell copyValue={session.sessionId} width={COL_WIDTHS.sessionId}>
   106→          <Text ff="monospace" size="sm" c="indigo">{shortId}</Text>
   107→        </CopyCell>
   108→
   109→        <CopyCell copyValue={absoluteTime(session.updatedAt)} width={COL_WIDTHS.updated}>
