   142→      const allCheckpointIds = [...new Set(allMetas.map((m) => m.checkpointId))];
   143→      const cpUserRows = allCheckpointIds.length > 0
   144→        ? await db.checkpointMetadata.findMany({
   145→            where: { checkpointId: { in: allCheckpointIds } },
   146→            select: { checkpointId: true, gitUserName: true, gitUserEmail: true },
   147→          })
   148→        : [];
   149→      const cpUserMap = new Map(cpUserRows.map((r) => [r.checkpointId, r]));
   150→
   151→      const shadows = await db.shadowSession.findMany();
   152→      const shadowMap = new Map(shadows.map((s) => [s.sessionId, s]));
   153→
   154→      const showArchived = _req.query.archived === "1";
   155→      const archivedRows = await db.archivedSession.findMany({ select: { sessionId: true } });
   156→      const archivedSet = new Set(archivedRows.map((r) => r.sessionId));
   157→
   158→      // Also include sessions visible only from LogEvent (hook-written, not yet indexed)
   159→      const knownIds = new Set([...cpMap.keys(), ...shadows.map((s) => s.sessionId)]);
   160→      const logEventSessionRows = await db.logEvent.findMany({
   161→        distinct: ["sessionId"],
   162→        where: { sessionId: { not: null } },
   163→        select: { sessionId: true },
   164→      });
   165→      for (const r of logEventSessionRows) {
   166→        if (r.sessionId && !knownIds.has(r.sessionId)) knownIds.add(r.sessionId);
   167→      }
   168→
   169→      const allIds = [...knownIds]
   170→        .filter((id) => showArchived ? archivedSet.has(id) : !archivedSet.has(id));
   171→      if (allIds.length === 0) {
   172→        res.json([]);
   173→        return;
   174→      }
   175→
   176→      // Min/max LogEvent timestamps per session
   177→      const times = await db.logEvent.groupBy({
   178→        by: ["sessionId"],
   179→        where: { sessionId: { in: allIds }, timestamp: { not: null } },
   180→        _min: { timestamp: true },
   181→        _max: { timestamp: true },
   182→      });
   183→      const timeMap = new Map(
   184→        times.map((r) => [r.sessionId!, { startedAt: r._min.timestamp, updatedAt: r._max.timestamp }])
   185→      );
   186→
   187→      // First cwd per session
   188→      const cwdRows = await db.logEvent.findMany({
   189→        where: { sessionId: { in: allIds }, cwd: { not: null } },
   190→        distinct: ["sessionId"],
   191→        orderBy: { id: "asc" },
   192→        select: { sessionId: true, cwd: true },
   193→      });
   194→      const cwdMap = new Map(cwdRows.map((e) => [e.sessionId!, e.cwd]));
   195→
   196→      // Parent-child relationships from task checkpoints
   197→      const allParentRows = await db.sessionParent.findMany({
   198→        select: { childSessionId: true, parentSessionId: true },
   199→      });
   200→      const parentMap = new Map(allParentRows.map((r) => [r.childSessionId, r.parentSessionId]));
   201→      const childMap = new Map<string, string[]>();
   202→      for (const r of allParentRows) {
   203→        if (!childMap.has(r.parentSessionId)) childMap.set(r.parentSessionId, []);
   204→        childMap.get(r.parentSessionId)!.push(r.childSessionId);
   205→      }
   206→
   207→      const result: SessionResponse[] = allIds.map((sessionId) => {
   208→        const cp     = cpMap.get(sessionId) ?? null;
   209→        const shadow = shadowMap.get(sessionId) ?? null;
   210→        const t      = timeMap.get(sessionId);
   211→        const startedAt = t?.startedAt ?? shadow?.createdAt ?? null;
   212→        const updatedAt = t?.updatedAt ?? shadow?.createdAt ?? null;
   213→        const cpUser = cp ? cpUserMap.get(cp.checkpointId) ?? null : null;
   214→        return {
   215→          sessionId,
   216→          startedAt: startedAt?.toISOString() ?? new Date(0).toISOString(),
   217→          updatedAt: updatedAt?.toISOString() ?? new Date(0).toISOString(),
   218→          cwd:             cwdMap.get(sessionId) ?? shadow?.cwd ?? "",
   219→          repoRoot:        repoDir ?? null,
   220→          repoName:        repoName,
   221→          parentSessionId: parentMap.get(sessionId) ?? null,
   222→          childSessionIds: childMap.get(sessionId) ?? [],
   223→          gitUserName:     cpUser?.gitUserName ?? gitUser.name,
   224→          gitUserEmail:    cpUser?.gitUserEmail ?? gitUser.email,
   225→          prompt:          shadow?.prompt ?? null,
   226→          summary:         null,
