import * as vscode from "vscode";
import { watch, FSWatcher } from "fs";
import { join, basename } from "path";
import { homedir } from "os";
import { execSync } from "child_process";
import {
  getDb,
  indexAllCheckpointsV2,
  indexAllShadowBranches,
  setupLogContentFts,
  type PrismaClient,
} from "@gossamer/core";

// ── Session shape (mirrors the server.ts SessionResponse) ────────────────────

interface Session {
  sessionId: string;
  startedAt: string;
  updatedAt: string;
  cwd: string;
  repoRoot: string | null;
  repoName: string | null;
  parentSessionId: string | null;
  childSessionIds: string[];
  gitUserName: string | null;
  gitUserEmail: string | null;
  prompt: string | null;
  summary: string | null;
  keywords: string[];
  branch: string | null;
  intent: string | null;
  isLive: boolean;
}

function gitConfigGet(key: string, cwd?: string): string | null {
  try {
    return execSync(`git config ${key}`, {
      cwd,
      encoding: "utf8",
      stdio: ["ignore", "pipe", "ignore"],
    }).trim() || null;
  } catch { return null; }
}

function getGitUser(cwd?: string): { name: string | null; email: string | null } {
  const name  = (cwd ? gitConfigGet("user.name", cwd)  : null) ?? gitConfigGet("--global user.name");
  const email = (cwd ? gitConfigGet("user.email", cwd) : null) ?? gitConfigGet("--global user.email");
  return { name, email };
}

async function getSessions(
  db: PrismaClient,
  repoPath: string,
  includeArchived: boolean,
): Promise<Session[]> {
  const repoName  = basename(repoPath);
  const gitUser   = getGitUser(repoPath);

  const allMetas = await db.checkpointSessionMetadata.findMany({
    select: {
      sessionId: true,
      checkpointId: true,
      branch: true,
      summary: { select: { intent: true } },
    },
    orderBy: { createdAt: "asc" },
  });
  const cpMap = new Map<string, { branch: string | null; intent: string | null; checkpointId: string }>();
  for (const m of allMetas) {
    cpMap.set(m.sessionId, { branch: m.branch, intent: m.summary?.intent ?? null, checkpointId: m.checkpointId });
  }

  const allCheckpointIds = [...new Set(allMetas.map((m) => m.checkpointId))];
  const cpUserRows = allCheckpointIds.length > 0
    ? await db.checkpointMetadata.findMany({
        where: { checkpointId: { in: allCheckpointIds } },
        select: { checkpointId: true, gitUserName: true, gitUserEmail: true },
      })
    : [];
  const cpUserMap = new Map(cpUserRows.map((r) => [r.checkpointId, r]));

  const shadows = await db.shadowSession.findMany();
  const shadowMap = new Map(shadows.map((s) => [s.sessionId, s]));

  const archivedRows = await db.archivedSession.findMany({ select: { sessionId: true } });
  const archivedSet  = new Set(archivedRows.map((r) => r.sessionId));

  const knownIds = new Set([...cpMap.keys(), ...shadows.map((s) => s.sessionId)]);
  const logEventSessionRows = await db.logEvent.findMany({
    distinct: ["sessionId"],
    where: { sessionId: { not: null } },
    select: { sessionId: true },
  });
  for (const r of logEventSessionRows) {
    if (r.sessionId && !knownIds.has(r.sessionId)) knownIds.add(r.sessionId);
  }

  const allIds = [...knownIds].filter((id) =>
    includeArchived ? archivedSet.has(id) : !archivedSet.has(id),
  );
  if (allIds.length === 0) return [];

  const times = await db.logEvent.groupBy({
    by: ["sessionId"],
    where: { sessionId: { in: allIds }, timestamp: { not: null } },
    _min: { timestamp: true },
    _max: { timestamp: true },
  });
  const timeMap = new Map(
    times.map((r) => [r.sessionId!, { startedAt: r._min.timestamp, updatedAt: r._max.timestamp }]),
  );

  const cwdRows = await db.logEvent.findMany({
    where: { sessionId: { in: allIds }, cwd: { not: null } },
    distinct: ["sessionId"],
    orderBy: { id: "asc" },
    select: { sessionId: true, cwd: true },
  });
  const cwdMap = new Map(cwdRows.map((e) => [e.sessionId!, e.cwd]));

  const allParentRows = await db.sessionParent.findMany({
    select: { childSessionId: true, parentSessionId: true },
  });
  const parentMap = new Map(allParentRows.map((r) => [r.childSessionId, r.parentSessionId]));
  const childMap  = new Map<string, string[]>();
  for (const r of allParentRows) {
    if (!childMap.has(r.parentSessionId)) childMap.set(r.parentSessionId, []);
    childMap.get(r.parentSessionId)!.push(r.childSessionId);
  }

  const result: Session[] = allIds.map((sessionId) => {
    const cp     = cpMap.get(sessionId) ?? null;
    const shadow = shadowMap.get(sessionId) ?? null;
    const t      = timeMap.get(sessionId);
    const startedAt = t?.startedAt ?? shadow?.createdAt ?? null;
    const updatedAt = t?.updatedAt ?? shadow?.createdAt ?? null;
    const cpUser = cp ? cpUserMap.get(cp.checkpointId) ?? null : null;
    return {
      sessionId,
      startedAt:       startedAt?.toISOString() ?? new Date(0).toISOString(),
      updatedAt:       updatedAt?.toISOString() ?? new Date(0).toISOString(),
      cwd:             cwdMap.get(sessionId) ?? shadow?.cwd ?? "",
      repoRoot:        repoPath,
      repoName,
      parentSessionId: parentMap.get(sessionId) ?? null,
      childSessionIds: childMap.get(sessionId) ?? [],
      gitUserName:     cpUser?.gitUserName ?? gitUser.name,
      gitUserEmail:    cpUser?.gitUserEmail ?? gitUser.email,
      prompt:          shadow?.prompt ?? null,
      summary:         null,
      keywords:        [],
      branch:          cp?.branch ?? shadow?.gitBranch ?? null,
      intent:          cp?.intent ?? null,
      isLive:          shadow !== null,
    };
  });

  result.sort((a, b) => b.updatedAt.localeCompare(a.updatedAt));
  return result;
}

// ── Panel ─────────────────────────────────────────────────────────────────────

export class GossamerPanel {
  private static instance: GossamerPanel | undefined;

  private readonly panel: vscode.WebviewPanel;
  private readonly repoPath: string;
  private readonly dbPath: string;
  private db: PrismaClient | null = null;
  private watcher: FSWatcher | undefined;
  private disposables: vscode.Disposable[] = [];

  static createOrShow(context: vscode.ExtensionContext, repoPath: string) {
    if (GossamerPanel.instance) {
      GossamerPanel.instance.panel.reveal();
      return;
    }
    GossamerPanel.instance = new GossamerPanel(context, repoPath);
  }

  static dispose() {
    GossamerPanel.instance?.cleanup();
    GossamerPanel.instance = undefined;
  }

  private constructor(context: vscode.ExtensionContext, repoPath: string) {
    this.repoPath = repoPath;
    this.dbPath   = join(homedir(), ".gossamer", "vscode.db");

    this.panel = vscode.window.createWebviewPanel(
      "gossamer",
      "Gossamer",
      vscode.ViewColumn.Two,
      {
        enableScripts: true,
        retainContextWhenHidden: true,
        localResourceRoots: [
          vscode.Uri.joinPath(context.extensionUri, "dist", "webview"),
        ],
      },
    );

    this.panel.webview.html = this.getWebviewHtml(context);

    this.panel.webview.onDidReceiveMessage(
      (msg) => this.handleMessage(msg),
      undefined,
      this.disposables,
    );

    this.panel.onDidDispose(() => this.cleanup(), undefined, this.disposables);

    this.indexAndNotify().catch(console.error);
    this.watchGitBranch();
  }

  private async getDb(): Promise<PrismaClient> {
    if (!this.db) this.db = await getDb(this.dbPath);
    return this.db;
  }

  private async indexAndNotify() {
    try {
      const db = await this.getDb();
      await setupLogContentFts(db);
      await indexAllCheckpointsV2(db, this.repoPath);
      await indexAllShadowBranches(db, this.repoPath);
      this.panel.webview.postMessage({ type: "indexed" });
    } catch (err) {
      console.error("[Gossamer] indexing error", err);
    }
  }

  private watchGitBranch() {
    const gitDir = join(this.repoPath, ".git");
    try {
      this.watcher = watch(gitDir, { recursive: false }, (_event, filename) => {
        if (filename === "packed-refs" || (filename ?? "").startsWith("refs/")) {
          this.indexAndNotify().catch(console.error);
        }
      });
    } catch {
      // git dir unavailable — no watch
    }
  }

  private async handleMessage(msg: { type: string; id?: string; method?: string; payload?: unknown }) {
    if (msg.type !== "request" || !msg.id || !msg.method) return;
    const { id, method, payload } = msg;

    try {
      const db   = await this.getDb();
      const data = await this.dispatch(db, method, payload as Record<string, unknown>);
      this.panel.webview.postMessage({ type: "response", id, data });
    } catch (err) {
      this.panel.webview.postMessage({ type: "response", id, error: String(err) });
    }
  }

  private async dispatch(
    db: PrismaClient,
    method: string,
    payload: Record<string, unknown>,
  ): Promise<unknown> {
    switch (method) {
      case "fetchSessions":
        return getSessions(db, this.repoPath, Boolean(payload?.includeArchived));

      case "archiveSession": {
        const sessionId = String(payload.sessionId);
        await db.archivedSession.upsert({
          where:  { sessionId },
          create: { sessionId },
          update: {},
        });
        return null;
      }

      case "unarchiveSession": {
        await db.archivedSession.deleteMany({ where: { sessionId: String(payload.sessionId) } });
        return null;
      }

      case "syncSessions": {
        await indexAllShadowBranches(db, this.repoPath);
        await indexAllCheckpointsV2(db, this.repoPath);
        this.panel.webview.postMessage({ type: "indexed" });
        return null;
      }

      default:
        throw new Error(`Unknown method: ${method}`);
    }
  }

  private getWebviewHtml(context: vscode.ExtensionContext): string {
    const webview  = this.panel.webview;
    const distUri  = vscode.Uri.joinPath(context.extensionUri, "dist", "webview");
    const scriptUri = webview.asWebviewUri(vscode.Uri.joinPath(distUri, "assets", "index.js"));
    const styleUri  = webview.asWebviewUri(vscode.Uri.joinPath(distUri, "assets", "index.css"));
    const nonce     = getNonce();

    return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta http-equiv="Content-Security-Policy"
    content="default-src 'none'; style-src ${webview.cspSource} 'unsafe-inline'; script-src 'nonce-${nonce}';" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <link href="${styleUri}" rel="stylesheet" />
  <title>Gossamer</title>
</head>
<body>
  <div id="root"></div>
  <script nonce="${nonce}" src="${scriptUri}"></script>
</body>
</html>`;
  }

  private cleanup() {
    this.watcher?.close();
    this.disposables.forEach((d) => d.dispose());
    this.disposables = [];
    GossamerPanel.instance = undefined;
  }
}

function getNonce(): string {
  const chars = "REDACTED";
  return Array.from({ length: 32 }, () =>
    chars[Math.floor(Math.random() * chars.length)],
  ).join("");
}

