// postMessage-based API for the VS Code webview.
// Replaces the HTTP/WebSocket api.ts used by the Electron app.

export interface Session {
  sessionId: string;
  startedAt: string;
  updatedAt: string;
  cwd: string;
  repoRoot: string | null;
  repoName: string | null;
  parentSessionId: string | null;
  childSessionIds: string[];
  gitUserName: string | null;
  gitUserEmail: string | null;
  prompt: string | null;
  summary: string | null;
  keywords: string[];
  branch: string | null;
  intent: string | null;
  isLive: boolean;
}

// acquireVsCodeApi() is injected by VS Code into the webview page.
// It can only be called once, so we call it here and export it.
declare function acquireVsCodeApi(): {
  postMessage(msg: unknown): void;
  getState(): unknown;
  setState(state: unknown): void;
};
export const vscode = acquireVsCodeApi();

// ── Request/response bridge ───────────────────────────────────────────────────

let msgId = 0;
const pending = new Map<
  string,
  { resolve: (v: unknown) => void; reject: (e: Error) => void }
>();

window.addEventListener("message", (event) => {
  const msg = event.data as {
    type: string;
    id?: string;
    data?: unknown;
    error?: string;
  };
  if (msg.type === "response" && msg.id) {
    const p = pending.get(msg.id);
    if (p) {
      pending.delete(msg.id);
      if (msg.error) p.reject(new Error(msg.error));
      else p.resolve(msg.data);
    }
  }
});

function request<T>(method: string, payload?: unknown): Promise<T> {
  return new Promise((resolve, reject) => {
    const id = String(++msgId);
    pending.set(id, { resolve: resolve as (v: unknown) => void, reject });
    vscode.postMessage({ type: "request", id, method, payload });
  });
}

// ── API surface ───────────────────────────────────────────────────────────────

export function fetchSessions(includeArchived = false): Promise<Session[]> {
  return request<Session[]>("fetchSessions", { includeArchived });
}

export function archiveSession(sessionId: string): Promise<void> {
  return request<void>("archiveSession", { sessionId });
}

export function unarchiveSession(sessionId: string): Promise<void> {
  return request<void>("unarchiveSession", { sessionId });
}

export function syncSessions(): Promise<void> {
  return request<void>("syncSessions");
}

/** Subscribe to re-index events broadcast by the extension host. */
export function subscribeToUpdates(onUpdate: () => void): () => void {
  const handler = (event: MessageEvent) => {
    const msg = event.data as { type: string };
    if (msg.type === "indexed") onUpdate();
  };
  window.addEventListener("message", handler);
  return () => window.removeEventListener("message", handler);
}

