    try {
      const [data, archivedData] = await Promise.all([
        fetchSessions(false),
        fetchSessions(true),
      ]);
      setSessions(archived ? archivedData : data);
      setArchivedIds(new Set(archivedData.map((s) => s.sessionId)));
